import { useState, useCallback } from "react";

const trailA = [
  { id:"vitoria", name:"Francisco de Vitoria", year:"1483–1546", quote:"Markets have natural laws ordained by God", detail:"Dominican friar at the University of Salamanca. Spain was running the largest empire on earth and debating whether colonizing indigenous people was moral. Vitoria said no — natural law applies to everyone. In that process he discovered that prices aren't set by kings or the Church but by common estimation among free people. His logic: God gave man free will, therefore exchange must be voluntary. Price-fixing by the state violates divine order. This wasn't economics as we know it — it was theology first. The free market was a consequence of God's design, not a human invention.", color:"#D4A053", connects:["azpilcueta","molina","threatened"] },
  { id:"azpilcueta", name:"Martín de Azpilcueta", year:"1491–1586", quote:"More money chasing goods raises prices", detail:"Scholar who noticed something nobody could explain — gold was flooding into Spain from the Americas but instead of getting richer, everything got more expensive. He figured out that when you increase the money supply without increasing goods, prices rise. That's the quantity theory of money — in 1556. This is the same principle central banks use today. But Azpilcueta saw it as evidence of divine natural order — God built self-correcting mechanisms into markets. Humans trying to override those mechanisms through state control is fighting against God's design. This insight predates any mainstream economist by two centuries.", color:"#C4913A", connects:["vitoria","molina","burial"] },
  { id:"molina", name:"Luis de Molina", year:"1535–1600", quote:"The just price is whatever buyers and sellers freely agree on", detail:"Jesuit theologian who took Vitoria's natural law framework and applied it directly to commerce. The medieval Church had long taught that there's a 'just price' set by moral authority. Molina flipped this — the just price IS the market price, because it emerges from free human choices, and free choice is God's gift. This demolished the Church's own justification for economic control. It also laid the groundwork for subjective value theory — the idea that things are worth what people are willing to pay, not what authorities say they're worth. Carl Menger would 'discover' this same idea 300 years later and get all the credit. Molina also argued that individual owners take better care of their property than collective owners — predicting the tragedy of the commons centuries before it was named.", color:"#B8842E", connects:["vitoria","threatened","smith"] },
  { id:"threatened", name:"THE THREAT", year:"Late 1500s", quote:"These ideas threatened every power structure that existed", detail:"Here's what nobody talks about: Salamanca's framework was dangerous to BOTH the Spanish crown AND the Catholic Church. If markets have divine natural laws, then kings can't manipulate prices, can't debase currency, can't fund wars through inflation. And if the just price is what free people agree on, the Church can't justify its own massive land holdings and wealth extraction. Salamanca was essentially telling every power structure — you're violating God's order. The Spanish Inquisition was active during this period. These monks were threading a needle between theological truth and institutional survival. The ideas didn't die because they were wrong. They died because they were inconvenient to everyone with power.", color:"#A07525", isMilestone:true, connects:["molina","burial"] },
  { id:"burial", name:"THE BURIAL", year:"1600s–1700s", quote:"The Enlightenment needed God out of economics", detail:"The Enlightenment project required that every field of knowledge be rebuilt on reason alone — no theology, no revelation, no divine authority. Locke, Hume, and the French physiocrats all engaged with economic questions but deliberately framed them as secular science. The monks' writings were in Latin, mostly unpublished outside of seminary libraries, and tied to a Catholic intellectual tradition that Protestant northern Europe had no interest in preserving. The burial wasn't one dramatic event — it was slow erasure through neglect, language barriers, and the deliberate secularization of every academic discipline. By the time Smith wrote, nobody in mainstream intellectual life knew Salamanca existed.", color:"#8B7355", isMilestone:true, connects:["threatened","smith","kant"] },
  { id:"smith", name:"Adam Smith", year:"1776", quote:"The invisible hand", detail:"Published The Wealth of Nations and became the 'father of economics.' But almost every core idea — supply and demand, subjective value, the self-regulating market — had already been worked out by Salamanca 200 years earlier. Smith's 'invisible hand' is essentially Vitoria's argument that God's order works through voluntary exchange, except Smith removed God and made it a metaphor. This wasn't plagiarism exactly — Smith likely never read Salamanca directly. But the ideas had filtered through generations of European thinkers. The effect was devastating: economics became a godless science. Free markets lost their theological foundation. And when critics later attacked capitalism as immoral, there was no spiritual defense left — because Smith had already stripped it out.", color:"#6B5B3E", connects:["burial","marx","rothbard"] },
  { id:"marx", name:"Karl Marx", year:"1867", quote:"Capital is dead labor vampirically feeding on the living", detail:"This is the gap most people miss. Once Smith stripped God out of free markets, Marx could attack them as purely human exploitation with no divine defense available. Marx's entire critique — that capitalism is a system of extraction where owners steal surplus value from workers — only works if you accept that markets are man-made and therefore man-can-unmake-them. If Salamanca's framework had survived, Marx would have been arguing against God's natural order, not just against factory owners. But because the theological foundation was gone, Marx could frame capitalism as a historical accident that could be overthrown. Das Kapital 1867 became the economic Bible for everyone who wanted to replace markets with state control. The void Salamanca left behind is exactly what Marx filled.", color:"#5A4E38", connects:["smith","ritschl","rauschenbusch"] },
  { id:"rothbard", name:"Murray Rothbard", year:"1970s", quote:"Salamanca are the true founders of economic science", detail:"Austrian economist who was writing a comprehensive history of economic thought and stumbled onto the Salamanca scholars. He was shocked — the monks had worked out supply and demand, subjective value, the quantity theory of money, and banking theory centuries before anyone else. Rothbard argued the entire Austrian economics tradition — Carl Menger, Ludwig von Mises, Friedrich Hayek — has roots running straight back to these monks through a chain of Spanish and Italian thinkers, not through Adam Smith. But Rothbard was a radical libertarian outsider. Mainstream academia dismissed him. The rediscovery got buried almost as fast as the original discovery.", color:"#4A3F2F", connects:["smith","grice","buried"] },
  { id:"grice", name:"Marjorie Grice-Hutchinson", year:"1952", quote:"Salamanca laid the foundations of modern economic theory", detail:"British economist living in Malaga, Spain who actually preceded Rothbard in recovering Salamanca. She learned Spanish, went into the archives, translated the original Latin texts, and published The School of Salamanca in 1952. She proved definitively that these monks had developed economic theory centuries before the Enlightenment claimed to invent it. But she was a woman in 1950s academia writing about obscure Spanish monks — the establishment ignored her for decades. Her work is the book in this entire thread. She connected dots that nobody wanted connected because they revealed that the entire origin story of modern economics is a lie.", color:"#3D3528", connects:["rothbard","buried"] },
  { id:"buried", name:"BURIED", year:"Present", quote:"The only God-centered economics ever created — gone", detail:"Today almost nobody knows that free market economics was born as theology. Econ departments teach Smith as the origin. Business schools teach markets as secular mechanisms. Churches teach nothing about economics at all. The result: when anyone today argues that capitalism is immoral, there is no theological counter-argument available. The only people who could have said 'free markets are God's design' were erased from history. The void they left is the exact space that the Social Gospel, liberation theology, and every form of Christian socialism walked into. You can't fight a theology with a spreadsheet. And that's all free market defenders have left.", color:"#2D2A22", isMilestone:true, connects:["rothbard","grice","installed"] },
];

const trailB = [
  { id:"kant", name:"Immanuel Kant", year:"1780s", quote:"Religion is moral duty, not divine truth", detail:"German philosopher who argued you can't prove God through logic — only through ethics. Religion's value is moral utility, not metaphysical truth. This opened the door: once religion is about what we SHOULD DO rather than what God DESIGNED, economics becomes a moral project, not a natural one. Kant didn't intend to destroy theology. But his framework made it possible for every thinker after him to strip divine revelation out of any field and replace it with human moral reasoning. Economics included.", color:"#4A6B8A", connects:["schleiermacher","ritschl","burial"] },
  { id:"schleiermacher", name:"Friedrich Schleiermacher", year:"1799", quote:"Theology is communal feeling, not fixed doctrine", detail:"Father of progressive Christianity. Published On Religion: Speeches to Its Cultured Despisers in 1799. Said theology isn't about creeds or metaphysics — it's about the feeling of absolute dependence on God within community. If theology responds to what the community FEELS rather than what God DECREED, then theology becomes infinitely flexible. Whatever the community is suffering becomes the theological priority. Salamanca said feelings are irrelevant — God's economic laws operate regardless of how you feel about prices. Schleiermacher made feelings the starting point. Every theology that follows him — including the Social Gospel — inherits this.", color:"#3D7A9E", connects:["kant","ritschl"] },
  { id:"ritschl", name:"Albrecht Ritschl", year:"1870s", quote:"The Kingdom of God is a social order, not heaven", detail:"THE critical link. Took Kant's moral framework and Schleiermacher's communal emphasis and fused them into one devastating idea: the Kingdom of God is NOT heaven after you die. It's a moral social order that humans build on earth through collective action. He defined it as 'the unity of humanity organized according to love.' He rejected original sin, the Trinity, the virgin birth, the Incarnation — anything metaphysical. Stripped Christianity down to ethics and social organization. His influence dominated German theology for 40 years. Every seminary student in that era absorbed his framework, including Rauschenbusch during his 1891 sabbatical in Germany. Without Ritschl, there is no Social Gospel.", color:"#2E8B9B", isMilestone:true, connects:["kant","schleiermacher","bushnell","rauschenbusch"] },
  { id:"bushnell", name:"Horace Bushnell", year:"Mid-1800s", quote:"The cross is social justice, not substitutionary atonement", detail:"American liberal theologian who dismantled orthodox doctrine from within. Denied that Christ died bearing the sins of humanity to satisfy God's justice — the doctrine of substitutionary atonement central to Christianity for 1800 years. Rauschenbusch followed him: Jesus died to 'substitute love for selfishness as the basis of human society.' If the cross isn't about saving individual souls, what is it for? Social transformation. The cross becomes a political act. Individual salvation is replaced by collective liberation. This is the single doctrine that makes the entire Social Gospel possible — because if salvation is still personal, there's no theological justification for the state to do the saving.", color:"#1F7A8A", connects:["ritschl","rauschenbusch"] },
  { id:"george", name:"Henry George", year:"1879", quote:"Land monopoly is the root of all poverty", detail:"American economist who published Progress and Poverty in 1879. Argued that poverty persists alongside economic progress because landlords capture all gains through rent. Solution: a single tax on land values. Rauschenbusch encountered George's ideas early in his New York pastorate and they radicalized his economic thinking. George was also the gateway drug for Fabian socialism — George Bernard Shaw credited George with converting four-fifths of British socialist leaders in the 1880s. George is the bridge between American reform Christianity and British Fabian strategy. Without him, Rauschenbusch doesn't connect to the Fabians.", color:"#1A7F8F", connects:["fabians","rauschenbusch"] },
  { id:"fabians", name:"Sidney & Beatrice Webb", year:"1884", quote:"Gradualist socialism through infiltration of institutions", detail:"Founded the Fabian Society in London. Named after the Roman general Fabius Maximus who defeated enemies through patience rather than direct battle. Not revolutionaries — gradualists. Their symbol was a tortoise. Explicit strategy: permeate universities, seminaries, government agencies, and churches with socialist ideas so slowly that nobody notices until it's complete. They also founded the London School of Economics in 1895 to institutionalize this approach. The Fabians had a dark side — early leaders including the Webbs and George Bernard Shaw advocated eugenics. Rauschenbusch visited England in 1891 and met them directly in 1907. This gave his theology its political delivery system.", color:"#166B7A", connects:["george","rauschenbusch","rockefeller"] },
  { id:"rockefeller", name:"THE FUNDING", year:"1890s–1900s", quote:"Rockefeller money built the seminaries that spread the Social Gospel", detail:"John D. Rockefeller funded the University of Rochester where Rauschenbusch studied, AND Rochester Theological Seminary where he taught. Rockefeller also founded the University of Chicago Divinity School. The richest capitalist in American history was bankrolling the seminaries that produced the theology calling capitalism sinful. Some historians argue Rockefeller genuinely believed in reform Christianity. Others argue he understood that a Social Gospel focused on government regulation was less threatening than actual worker revolution. Either way, the theology that says markets are sinful was incubated in institutions funded by the most successful market participant in history.", color:"#128090", isMilestone:true, connects:["fabians","rauschenbusch","fosdick"] },
  { id:"rauschenbusch", name:"Walter Rauschenbusch", year:"1907", quote:"Sin is institutional, not individual", detail:"Assembled the entire machine. Took Kant's moral religion + Schleiermacher's communal feeling + Ritschl's earthly Kingdom + Bushnell's social atonement + Henry George's land economics + Fabian gradualist strategy and packaged it as the Social Gospel. Published Christianity and the Social Crisis in 1907. His key move: redefining sin as 'super-personal forces' — the state and economic institutions are sinful entities requiring Christian salvation. If sin is systemic, only systemic power can redeem it. That means the state. Individual repentance is no longer enough. He also formed the Brotherhood of the Kingdom in 1892 — a Fabian-style permeation network within American churches.", color:"#0D5C6A", isMilestone:true, connects:["ritschl","bushnell","fabians","fosdick","king","marx"] },
  { id:"fosdick", name:"Harry Emerson Fosdick", year:"1920s–1940s", quote:"Rauschenbusch did more after his death than he ever did in his lifetime", detail:"Pastor of Riverside Church in New York — also funded by Rockefeller. Fosdick became the media megaphone for the Social Gospel after Rauschenbusch died in 1918. He's the bridge between Rauschenbusch's generation and the Civil Rights generation. Without Fosdick keeping the Social Gospel alive through the 1920s-40s, it might have died with World War I. Instead it was waiting, fully formed, when King arrived at seminary.", color:"#095565", connects:["rauschenbusch","rockefeller","mays","king"] },
  { id:"mays", name:"Benjamin Mays", year:"1940s", quote:"The church must address injustice in the here and now", detail:"President of Morehouse College during King's undergraduate years. Spoke against segregation every Tuesday morning in chapel. Mays was steeped in the Social Gospel tradition and transmitted it directly to a generation of Black leaders before they reached seminary. King called him his 'spiritual mentor.' Mays is the node where the Social Gospel officially enters the Black church's institutional pipeline. Before Mays, it was mostly a white liberal Protestant movement. After Mays, it becomes the theological engine of Black civil rights.", color:"#075060", connects:["fosdick","king","washington_dubois"] },
  { id:"king", name:"Martin Luther King Jr.", year:"1950s", quote:"Rauschenbusch left an indelible imprint on my thinking", detail:"Read Rauschenbusch at Crozer Theological Seminary. At Boston University he studied Reinhold Niebuhr and engaged seriously with Marx while rejecting communism. King is synthesizing Rauschenbusch's theology + Marx's economic critique + Niebuhr's political realism + the Black prophetic tradition into one framework. The result: the most powerful moral movement in American history, entirely built on the premise that the system — not the individual — must be redeemed, and only collective political action through state pressure can do it.", color:"#064D5A", connects:["rauschenbusch","mays","washington_dubois","jackson"] },
  { id:"washington_dubois", name:"THE SPLIT", year:"1895–1920s", quote:"Booker T. Washington vs. W.E.B. Du Bois — ownership vs. activism", detail:"Washington was building Black economic infrastructure — the National Negro Business League in 1900 had 600 chapters creating Black banks, insurance companies, supply chains. Black Wall Street in Tulsa was his philosophy made real. But Du Bois and the Talented Tenth said working within the market system was accommodation to white supremacy. The Black church, absorbing Social Gospel theology through seminaries, overwhelmingly sided with Du Bois. Then Tulsa happened in 1921 — the state destroyed Black Wall Street. Instead of proving Washington right, it was used to prove Du Bois right. That interpretation calcified. The theological and political framework for Black liberation became permanently state-oriented.", color:"#054858", isMilestone:true, connects:["mays","king","jackson"] },
  { id:"jackson", name:"Jesse Jackson", year:"1971", quote:"Economic justice through the state, not the market", detail:"Operation PUSH in 1971 and the Rainbow Coalition in 1984 institutionalized the Social Gospel as Black political infrastructure at the national level. The theology has become so embedded that it no longer looks like theology — it looks like common sense. 'Of course government should fix inequality' feels neutral. But it's Rauschenbusch's sermon, delivered through King's prophetic voice, institutionalized through Jackson's political machine.", color:"#003F4A", connects:["king","washington_dubois","installed"] },
  { id:"installed", name:"INSTALLED", year:"Present", quote:"The state replaced God — and most people don't know it's theology", detail:"When someone says 'the system is broken' — that's Rauschenbusch's super-personal forces. When someone says 'we need policy solutions' — that's Ritschl's earthly Kingdom. When someone says 'individual success doesn't matter if the community suffers' — that's Bushnell's rejection of individual salvation. When someone side-eyes a Black entrepreneur for 'selling out' — that's Du Bois defeating Washington with the Social Gospel's blessing. It's a complete replacement theology preached by people who have no idea they're standing in a chain that runs from Kant through the Fabians through a Baptist pastor in Hell's Kitchen to the present moment.", color:"#002A33", isMilestone:true, connects:["jackson","buried"] },
];

const inversions = [
  { from:"Individual sin", to:"Systemic sin" }, { from:"Personal salvation", to:"Government policy" }, { from:"Free markets as divine", to:"Free markets as evil" }, { from:"The church saves souls", to:"The state saves society" }, { from:"God's natural law", to:"Man's moral project" }, { from:"The cross redeems individuals", to:"The cross inspires social movements" }, { from:"Just price set by free exchange", to:"Just price set by regulation" }, { from:"Poverty as spiritual condition", to:"Poverty as systemic failure" }, { from:"Kingdom of God in heaven", to:"Kingdom of God on earth through policy" }, { from:"Entrepreneurship as sacred calling", to:"Entrepreneurship as selling out" },
];

const historicalEvents = [
  { id:"e1", name:"The Spanish Price Revolution", year:"1540s–1640s", verdict:"SALAMANCA PROVEN RIGHT", verdictColor:"#D4A053", detail:"Gold and silver flooded Spain from the Americas. Prices exploded. The Spanish crown tried price controls. It failed catastrophically — shortages everywhere, black markets booming. Azpilcueta had predicted exactly this. But the crown was deeply embedded in the economy — granting monopolies, controlling colonial trade, debasing coinage to fund wars. Spain never actually had free markets. The state was the biggest economic actor. When Spain's economy collapsed, critics blamed 'the market' when it was really state capture wearing a market costume." },
  { id:"e2", name:"The Dutch Golden Age", year:"1588–1672", verdict:"CLOSEST TEST OF FREE MARKETS", verdictColor:"#D4A053", detail:"The Dutch Republic became the wealthiest nation in Europe with the most market-oriented economy of its time — open trade, religious tolerance, the Amsterdam Stock Exchange, relatively low taxation. A tiny country with no natural resources became a global superpower. BUT the Dutch East India Company operated with government-granted monopoly powers. Colonial exploitation was state-sanctioned. The prosperity came from the free parts. The exploitation came from the state parts. Nobody separated the two." },
  { id:"e3", name:"The Gilded Age", year:"1870s–1900s", verdict:"MISREAD BY BOTH SIDES", verdictColor:"#C75A3A", detail:"The event that made the Social Gospel seem necessary. Robber barons, child labor, tenement slums. But the Gilded Age was NOT a free market. Railroads received 170 million acres of government land grants. Tariffs protected monopolies. State legislatures were openly bought. Courts crushed labor while protecting corporate consolidation. Banks operated under a cartel-like National Banking Act. The 'robber barons' were state-capture capitalists who used government power to eliminate competition. Salamanca would have condemned this. But because Salamanca was buried, nobody made that argument. The only theology available looked at state-captured markets and concluded ALL markets are evil." },
  { id:"e4", name:"Creation of the Federal Reserve", year:"1913", verdict:"SALAMANCA'S WORST NIGHTMARE", verdictColor:"#C75A3A", detail:"Created a central bank with power to expand and contract the money supply at will. Azpilcueta demonstrated that increasing money supply inflates prices. Juan de Mariana argued currency debasement is theft requiring popular consent. The Fed formalized that theft into permanent policy, controlled by unelected officials, with no popular consent. Juan de Salas wrote that just price factors are so complex 'only God, not man, can understand them exactly.' The Fed claims to know what interest rates should be — it claims knowledge Salamanca said only God possesses. Dollar has lost over 97% of purchasing power since." },
  { id:"e5", name:"Black Wall Street — Tulsa", year:"1921", verdict:"MOST MISINTERPRETED EVENT IN BLACK ECONOMIC HISTORY", verdictColor:"#C75A3A", detail:"The Greenwood District was proof of Washington's vision — 600 businesses, 21 churches, 30 grocery stores, Black-owned banks, a private airplane. An entirely self-sustaining Black economy. Then on May 31, 1921, a white mob — aided by local police and possibly National Guard planes — burned it to the ground. Up to 300 killed, 10,000 homeless. Black Wall Street proved Washington RIGHT. What destroyed it wasn't the market — it was the state. Police participated. National Guard interned survivors, not attackers. No prosecutions. The state didn't fail to protect Black capitalism — it actively destroyed it. But the Social Gospel said: see, the system will never let Black people succeed. The very institution that burned Greenwood became the proposed savior." },
  { id:"e6", name:"Weimar Hyperinflation", year:"1921–1923", verdict:"AZPILCUETA PROVEN RIGHT — CATASTROPHICALLY", verdictColor:"#D4A053", detail:"Germany printed money to pay war reparations. By November 1923 prices doubled every few days. Savings obliterated. The middle class destroyed. Azpilcueta's quantity theory in its most extreme form. The devastation directly fueled Hitler's rise. State money printing created the catastrophe. A different state intervention — fascism — was the response. At no point was 'let money be determined by free exchange' considered." },
  { id:"e7", name:"The New Deal", year:"1933–1939", verdict:"SOCIAL GOSPEL GOES FEDERAL", verdictColor:"#2E8B9B", detail:"FDR's New Deal was the Social Gospel made into law. But it embedded racial exclusion into its salvation. Agricultural and domestic workers — the two largest categories of Black employment — were deliberately excluded from Social Security and the National Labor Relations Act. FHA loans were denied to Black neighborhoods through redlining. The GI Bill was administered locally so Southern states excluded Black veterans. The state-as-savior saved white people and excluded Black people. Yet the response wasn't to abandon the state framework — it was to fight for inclusion IN it." },
  { id:"e8", name:"Civil Rights Act & Great Society", year:"1964–1968", verdict:"THE THEOLOGY BECOMES POLICY", verdictColor:"#2E8B9B", detail:"Trail B's full victory. King's theology became Johnson's legislation. But the Great Society contained a fundamental tension: urban renewal destroyed more Black housing than it built. Public housing concentrated poverty. Welfare rules penalized marriage and savings, destabilizing the Black family. Moynihan warned in 1965 — his report was denounced as racist. The state was doing exactly what Salamanca predicted — distorting natural order through intervention. But Salamanca was buried, so the only response was to demand MORE state intervention to fix what state intervention had broken." },
  { id:"e9", name:"Nixon Ends the Gold Standard", year:"1971", verdict:"MONEY FULLY UNMOORED FROM NATURAL LAW", verdictColor:"#C75A3A", detail:"August 15, 1971. Dollar's convertibility to gold ended unilaterally. Money now backed by nothing but government promise. The final severance from anything Salamanca would recognize. The monks operated with commodity money constrained by nature. Now money can be created from nothing, unlimited, at politicians' discretion. Every dollar printed after 1971 is what Juan de Mariana called theft through debasement — except now there's no metal to even debase. Wages stagnated relative to productivity from this exact year. Housing detached from income. Asset holders get richer while workers fall behind. The monks called this 400 years early." },
  { id:"e10", name:"2008 Financial Crisis & Bailouts", year:"2008", verdict:"STATE CAPTURE DISGUISED AS MARKET FAILURE", verdictColor:"#C75A3A", detail:"Universally cited as proof free markets are dangerous. But: the Fed held rates artificially low for years. Fannie Mae and Freddie Mac were created by Congress to subsidize mortgages. Rating agencies operated in a government-protected oligopoly. 'Too big to fail' was a state guarantee removing market discipline. When it collapsed, banks got $700 billion in bailout and the Fed printed trillions — inflating money supply as Azpilcueta warned. Homeowners got nothing. The narrative became: 'capitalism failed.' But the market was never free. Every layer traces to state intervention. The arsonist was hired as the firefighter." },
  { id:"e11", name:"COVID Money Printing & Inflation", year:"2020–2023", verdict:"AZPILCUETA'S 1556 WARNING IN REAL TIME", verdictColor:"#D4A053", detail:"The Federal Reserve created approximately 40% of all dollars in existence within two years. By 2022, inflation hit 9.1%. Grocery prices up 25%. Housing up 30-40%. Azpilcueta's quantity theory at a scale he couldn't have imagined — with the exact mechanism he described in 1556. The Fed then raised rates aggressively to fight inflation IT created. Those hurt worst: people on fixed incomes and without assets — disproportionately Black and brown communities. The Social Gospel response: demand more government aid funded by more money creation. Salamanca's response: stop manipulating the money supply. The poor pay the price every time." },
  { id:"e13", name:"Samuelson's Textbook Captures the Classroom", year:"1948–Present", verdict:"THE FABIAN STRATEGY'S GREATEST TRIUMPH", verdictColor:"#2E8B9B", detail:"In 1948, MIT economist Paul Samuelson published Economics, which became the most influential textbook in history — over 4 million copies sold across 41 editions, translated into 40+ languages, and the template for virtually every Econ 101 course worldwide. Samuelson was a committed Keynesian who presented government management of the economy as settled science. His framework became THE framework: markets are useful but inherently unstable, prone to 'market failures' requiring government correction. Central banks must manage money supply. Government spending fills demand gaps. This is Ritschl's earthly Kingdom dressed in equations — but because it was presented as math, nobody recognized it as theology. The Fabian strategy of institutional permeation reached its ultimate form. The pipeline works like this: Samuelson's Keynesian textbook trains students to see markets as flawed and government as the fix. Those students become teachers, journalists, lawyers, and politicians. The ones who go to graduate school encounter more radical frameworks — critical theory, post-colonial studies, dependency theory — which feel like natural extensions of what they already 'know' from Econ 101. By the time a student is calling themselves a Marxist or a democratic socialist, they weren't radicalized by Marx. They were pre-loaded by Samuelson. Marx just gave vocabulary to conclusions their introductory textbook had already planted. Meanwhile, the Austrian school — Salamanca's intellectual descendants through Menger, Mises, Hayek — is taught in maybe 5 universities in the entire country. Salamanca itself appears in zero standard textbooks. A student can get a PhD in economics from any elite university without ever encountering the idea that free markets might be divine natural order. The monks who said 'only God can know the just price' are in no syllabus on earth. The economists who say 'we can manage the economy' are in every syllabus on earth. That's not an accident. That's the Fabian tortoise arriving at its destination." },
  { id:"e12", name:"Bitcoin & Black Tech Entrepreneurship", year:"2009–Present", verdict:"THE THEOLOGICAL ORPHAN RETURNS", verdictColor:"#D4A053", detail:"Bitcoin's 21 million coin hard cap is Azpilcueta's 1556 warning coded into software — a money supply no king, no central bank, no politician can inflate. A new generation of Black entrepreneurs in tech and Bitcoin is recreating Washington's vision — building wealth outside state systems, creating parallel financial infrastructure. They get the same pushback: 'You're abandoning the community.' 'Individual wealth doesn't solve systemic racism.' Du Bois vs. Washington replaying with the same Social Gospel theology underneath. But Bitcoin operates where the state has less control — decentralized, borderless, unseizable if held properly. They don't know they're living in Trail A. They've never heard of Vitoria. They have no theological framework for what they're doing. They just know the state hasn't worked." },
];

const scholasticPredictions = [
  { id:"p1", monk:"Martín de Azpilcueta", year:"1556", prediction:"Increasing the money supply without increasing goods will cause prices to rise", modern:"Federal Reserve money printing → 2021-2023 inflation at 9.1%. Dollar has lost 97% of purchasing power since 1913. Every episode of hyperinflation — Weimar, Zimbabwe, Venezuela — follows this exact pattern.", color:"#D4A053" },
  { id:"p2", monk:"Francisco de Vitoria", year:"1530s", prediction:"Government price-fixing creates shortages and black markets", modern:"Nixon's 1971 price controls created shortages within months. Venezuela's food price controls led to empty shelves. COVID-era rent controls reduced available housing. Every city with rent control has a housing shortage. Every country with price controls has black markets.", color:"#C4913A" },
  { id:"p3", monk:"Juan de Salas", year:"1617", prediction:"The just price is so complex that only God, not man, can understand it exactly", modern:"Central banks consistently fail to predict inflation, recessions, or their own policy effects. The Fed called 2021 inflation 'transitory.' Missed 2008 entirely. Soviet planners couldn't set bread prices correctly. No committee has ever outperformed the distributed knowledge of millions of free exchanges.", color:"#B8842E" },
  { id:"p4", monk:"Juan de Mariana", year:"1609", prediction:"Currency debasement by the state is theft from the people and requires popular consent", modern:"Nixon ended the gold standard without popular vote. QE created trillions with no public referendum. Every dollar printed dilutes the purchasing power of every dollar held by working people. Inflation is a hidden tax requiring no legislation, no vote, no consent. Mariana called it theft. Modern economists call it 'monetary policy.' The monks were more honest.", color:"#A07525" },
  { id:"p5", monk:"Luis de Molina", year:"1590s", prediction:"Private owners take better care of their property than collective owners", modern:"Soviet collective farms produced chronic shortages while American private farms produced surpluses. Public housing deteriorated within years while owner-occupied homes were maintained for generations. Every experiment in collective ownership has confirmed Molina's observation — 200 years before Marx proposed the alternative.", color:"#8B7355" },
  { id:"p6", monk:"Diego de Covarrubias", year:"1550s", prediction:"People have the exclusive right to benefit from their own property — except in genuine emergency", modern:"Eminent domain transfers property to political developers. Civil asset forfeiture lets police seize property without conviction. COVID lockdowns destroyed millions of small businesses while connected corporations stayed open. Covarrubias drew a narrow emergency exception. The modern state made the emergency permanent.", color:"#6B5B3E" },
  { id:"p7", monk:"Francisco de Vitoria", year:"1530s", prediction:"Governments should not interfere with trade relations established between free people", modern:"Every tariff raises consumer prices. Every trade war reduces prosperity on both sides. Smoot-Hawley tariffs of 1930 deepened the Great Depression. 500 years of data confirming what Vitoria taught from a monastery in Spain.", color:"#5A4E38" },
];

const fallacies = [
  { id:"f1", name:"'Capitalism is driven by greed'", origin:"Rooted in Rauschenbusch's reframing of self-interest as sin. Smith originally argued self-interest produces public benefit through competition. Salamanca went further: voluntary exchange is God's design for mutual benefit. Rauschenbusch inverted this — self-interest became 'selfishness,' the original sin of capitalism.", firstDisproven:"Every communist and socialist state that replaced market incentives with collective duty — USSR, Mao's China, Cuba, Venezuela — produced less for its citizens. Soviet GDP never exceeded 40% of America's. The 'greedy' system fed people. The 'moral' system starved them. Exposed repeatedly from the 1920s onward, but the fallacy persists because the Social Gospel gave it theological authority that economic data can't override.", stillActive:"Every corporate scandal is cited as proof capitalism is 'greedy' while ignoring that each involved regulatory capture, government guarantees, or state-granted advantages. The greed was enabled by the state, not the market.", color:"#8B3A3A" },
  { id:"f2", name:"'The rich get richer and the poor get poorer'", origin:"Marx's immiseration thesis from Das Kapital 1867. He predicted capitalism would concentrate wealth until workers had nothing. Rauschenbusch theologized it: the rich getting richer is systemic sin.", firstDisproven:"Global extreme poverty fell from 90% in 1820 to under 10% by 2015 — the largest reduction in human suffering in history — driven almost entirely by market economies. Marx's prediction was the exact opposite of what happened.", stillActive:"Inequality (relative gap) is conflated with poverty (absolute condition). A society where the rich have $10M and the poor have $50K has more inequality than one where everyone has $500 — but less poverty. The fallacy survives because the Social Gospel measures sin by inequality, not by actual human flourishing.", color:"#7A3A4A" },
  { id:"f3", name:"'Profit is exploitation of workers'", origin:"Marx's labor theory of value — a product's value comes from labor input, so profit is stolen labor. Already wrong when Marx wrote it. Molina in the 1590s demonstrated that value is subjective — determined by what buyers will pay, not by labor hours.", firstDisproven:"Molina's subjective value theory was independently rediscovered by Carl Menger in 1871 and became the foundation of modern microeconomics. The 'marginal revolution' formally destroyed the labor theory of value within a decade of Marx publishing it. The monks had this right 300 years before Marx got it wrong.", stillActive:"Still taught in sociology and political science departments. Still the implicit framework behind 'living wage' arguments, 'profit is theft' rhetoric, and every critique of CEO pay ratios. Persists because the Scholastic correction was buried with Salamanca, and the Social Gospel gave Marx's error a Christian veneer.", color:"#6A3A5A" },
  { id:"f4", name:"'Without government regulation, markets produce chaos'", origin:"Emerged from misreading the Gilded Age. Reformers saw industrial abuse and concluded markets are inherently exploitative without state control. The Social Gospel codified this as theology. The Fabians made it political strategy.", firstDisproven:"The Gilded Age's worst abuses were enabled by government land grants, tariffs, court injunctions, and corporate charters limiting liability. The chaos wasn't from lack of regulation — it was from regulation that benefited insiders. Airlines deregulated in 1978 — prices dropped and service improved. Trucking deregulated in 1980 — same result. Every deregulation episode contradicts the fallacy.", stillActive:"The default assumption of every policy debate. Each regulation creates compliance costs that large corporations absorb but small competitors cannot — meaning regulation increases the monopoly power it claims to prevent. Salamanca explains why: state interference in natural market order always produces distortions, and the powerful always capture the interfering state.", color:"#5A3A6A" },
  { id:"f5", name:"'Minimum wage helps the poor'", origin:"Progressive Era labor reform, theologically supported by Social Gospel's framing of low wages as systemic sin requiring state redemption.", firstDisproven:"Every minimum wage increase above market clearing price increases unemployment among the least skilled — disproportionately young Black men. South Africa's farmworker minimum wage in 2003 led to mass layoffs. American Samoa's federally mandated minimum wage destroyed its tuna industry. Vitoria explained in the 1530s: when the state sets prices above what free exchange determines, the result is surplus — in labor markets, that's unemployment.", stillActive:"Treated as moral self-evidence. The unseen victims — the teenager who doesn't get hired, the small business that closes, the Black community with 30%+ youth unemployment — are invisible because the Social Gospel framework counts intentions, not consequences. Salamanca counted consequences because they believed God's natural order reveals truth through outcomes, not feelings.", color:"#4A3A7A" },
  { id:"f6", name:"'Essential services must be publicly owned'", origin:"Fabian socialism's core doctrine. Sidney Webb argued utilities, transportation, and healthcare are too important for profit motives. The Social Gospel baptized this: if salvation is collective, the means of collective life must be collectively owned.", firstDisproven:"British Rail (nationalized 1948) became a byword for delay and decay. Soviet healthcare produced lower life expectancy than Western market systems. US public schools in low-income areas consistently underperform private alternatives. The US Postal Service runs perpetual deficits while FedEx and UPS profit. Molina predicted this in the 1590s: private owners take better care of their property.", stillActive:"Healthcare, education, and housing are still treated as sectors where markets 'can't work' — despite abundant evidence that market competition improves quality and reduces cost when actually permitted. The fallacy survives because the Social Gospel made public ownership a moral position. Questioning it feels like questioning compassion.", color:"#3A4A7A" },
  { id:"f7", name:"'Government spending stimulates the economy'", origin:"Keynes formalized this in 1936, but the idea was implicit in the Social Gospel from 1907 — the state as redeemer, government action as salvation. The New Deal was the first large-scale test.", firstDisproven:"The New Deal didn't end the Great Depression — WWII did. The depression of 1920-21 was sharper than 1929 but recovered in 18 months because government CUT spending. Japan's 'lost decades' from 1990-present featured massive stimulus producing only debt. Every dollar the government spends must first be taxed, borrowed, or printed — each takes resources from the private economy. Azpilcueta understood in 1556: you cannot create wealth by moving it from one pocket to another.", stillActive:"The default recession response. COVID stimulus in 2020 created $5 trillion in spending that produced 9.1% inflation — the exact outcome Azpilcueta described 464 years earlier. Persists because the Social Gospel made state action morally superior to market adjustment. Doing nothing feels like abandoning people. But the monks understood: the market's self-correction is God's correction. Interfering with it doesn't prevent pain — it delays and compounds it.", color:"#3A5A7A" },
  { id:"f8", name:"'Slavery built American capitalism'", origin:"This is the slyest one. Marxist historians like Eric Williams (Capitalism and Slavery, 1944) and the New History of Capitalism school (Edward Baptist, Sven Beckert) embedded the idea that slavery wasn't a pre-capitalist institution that capitalism eventually destroyed — but that slavery WAS capitalism in its purest form. The trick: define capitalism as 'any system of exploitation' rather than 'voluntary exchange between free people.' Once you do that, slavery becomes capitalism's origin story rather than its antithesis. This reframing was then absorbed into Black liberation theology and the Social Gospel tradition as proof that free markets are inherently built on Black suffering.", firstDisproven:"Slavery existed for thousands of years before capitalism — in Rome, Egypt, West Africa, the Ottoman Empire, and every civilization on earth. It was the ABOLITION of slavery that correlated with the rise of free market ideology. Britain abolished slavery in 1833 — the most capitalist nation on earth at the time. The American South was the LEAST market-oriented region of the US — it was an aristocratic, agrarian, state-protected plantation system that relied on government enforcement of fugitive slave laws, state militias, and legal frameworks that prohibited free labor markets. Salamanca's monks actually used their natural law framework to argue against Spanish enslavement of indigenous people in the 1500s. Free market theology was the FIRST intellectual tradition to declare exploitation a violation of divine order. Slavery wasn't capitalism — slavery was state capture of human beings.", stillActive:"Taught in most American universities as settled history. The 1619 Project embedded it into K-12 curriculum. Any pushback is labeled as 'defending slavery' — which is the rhetorical trap. The framing makes it impossible to argue that free markets are liberating without appearing to minimize slavery. The effect: Black Americans are taught that the very system that historically destroyed slavery is the system that created it. The theological framework that first condemned exploitation (Salamanca) is buried, so the only available narrative is that markets equal chains.", color:"#6A2A3A" },
  { id:"f9", name:"'The Great Depression proved free markets fail'", origin:"The single most important historical event in the Marxist-progressive narrative. FDR's New Deal is taught as the moment government heroically saved capitalism from itself. This reading was canonized by Arthur Schlesinger Jr., John Kenneth Galbraith, and mainstream academia. The Social Gospel movement pointed to the Depression as ultimate proof that Rauschenbusch was right — unregulated markets produce catastrophe, only the state can provide redemption.", firstDisproven:"Milton Friedman and Anna Schwartz demonstrated in A Monetary History of the United States (1963) that the Federal Reserve — a government institution created in 1913 — caused the Depression by contracting the money supply by over 30% between 1929 and 1933. The Smoot-Hawley Tariff of 1930 — a government policy — collapsed international trade by 65%. FDR's own Treasury Secretary Henry Morgenthau admitted in 1939: 'We have tried spending money. We are spending more than we have ever spent before and it does not work.' Unemployment was still at 17% in 1939, six years into the New Deal. The Depression of 1920-21 was equally severe in its initial decline but recovered in 18 months with zero government intervention — the government actually CUT spending and the Fed raised rates. Nobody teaches 1920-21 because it destroys the narrative that government intervention is necessary for recovery.", stillActive:"The New Deal remains the template for every economic crisis response: 2008 bailouts, COVID stimulus, infrastructure spending. 'We need a new New Deal' is a recurring political slogan. The Depression is still taught as market failure in virtually every textbook despite Friedman's Nobel Prize-winning demonstration that it was government failure. The myth persists because the Social Gospel needs it — without the Depression narrative, the entire case for state-as-savior collapses. It's not just bad history. It's load-bearing theology.", color:"#5A2A4A" },
  { id:"f10", name:"'Colonialism made the West rich and the Third World poor'", origin:"Marxist dependency theory, formalized by Andre Gunder Frank (1966) and Immanuel Wallerstein's world-systems theory (1974). The argument: Western wealth was extracted from colonies, so global poverty is caused by capitalism, not by local governance failures. This was woven into liberation theology and the Social Gospel's international expansion — Third World poverty became another form of systemic sin requiring collective (state-led, foreign-aid-based) redemption.", firstDisproven:"The wealthiest nations in Europe — Switzerland, Scandinavia — had no significant colonies. The nations with the largest colonial empires — Spain, Portugal — became the poorest in Western Europe. Hong Kong and Singapore — former colonies with zero natural resources — became wealthier per capita than their former colonizer Britain by embracing free markets. Botswana, the most market-friendly economy in sub-Saharan Africa, went from one of the poorest countries on earth at independence in 1966 to an upper-middle-income country in two generations. Meanwhile, resource-rich nations that chose state-controlled economies after independence — Zimbabwe, Venezuela, Tanzania under Nyerere — collapsed. Colonialism was real and devastating, but the divergence in post-colonial outcomes proves that economic systems after independence matter more than colonial history. Countries that chose markets prospered. Countries that chose state control did not.", stillActive:"The default explanation for global inequality in every university, NGO, and international institution. Any suggestion that post-colonial governance choices matter is labeled 'blaming the victim.' Foreign aid — the practical application of this fallacy — has transferred over $4.6 trillion to developing countries since 1960 with minimal impact on growth, while the countries that rejected aid and embraced trade (East Asian tigers) experienced the fastest poverty reduction in human history. The fallacy survives because it serves the Social Gospel's need for a global systemic villain — and because admitting that free markets lift the poor would validate Salamanca and invalidate the entire state-intervention framework.", color:"#4A2A5A" },
  { id:"f11", name:"'Automation and technology destroy jobs'", origin:"The Luddite fallacy, recycled by Marx as 'the reserve army of labor' — the idea that machines replace workers, creating permanent unemployment that only the state can address. Every generation of Marxist and progressive thinkers has predicted that the current wave of technology will finally make this true. The Social Gospel absorbed it: if technology destroys livelihoods, the state must provide through redistribution, universal basic income, or guaranteed employment.", firstDisproven:"Every single time. The industrial revolution was supposed to destroy all craft jobs — instead it created factory jobs that paid more. Automobiles were supposed to destroy the horse-and-buggy economy — instead they created millions of jobs in manufacturing, road construction, gas stations, suburbs, and tourism. ATMs were supposed to eliminate bank tellers — the number of bank tellers actually increased because cheaper branch operations meant more branches. The number of jobs in the US economy has increased from 30 million in 1900 to over 160 million today despite (because of) continuous automation. Molina understood why in the 1590s: when production becomes more efficient, goods become cheaper, people have more money to spend on other things, and new industries emerge to meet that new demand. This is God's natural order of abundance — human creativity is infinite because it's made in God's image.", stillActive:"The current iteration is 'AI will take all the jobs.' Every previous prediction was wrong but this time it's supposed to be different. The same arguments used against the power loom in 1810, the assembly line in 1913, the computer in 1970, and the internet in 1995 are being recycled word for word. The fallacy persists because it serves the Social Gospel's need for a perpetual crisis that only the state can solve. If technology actually creates more prosperity and more jobs — as it has every single time — then you don't need the state as savior. And the entire theological framework collapses.", color:"#3A2A6A" },
  { id:"f12", name:"'Housing is a human right that the market can't provide'", origin:"Embedded through decades of Marxist-influenced urban planning theory. The argument: housing is too essential to be left to market forces, so government must provide public housing, impose rent controls, mandate affordable units, and restrict developer profits. The Social Gospel baptized this — shelter is a basic need, therefore providing it is the state's moral obligation. Anyone who disagrees is callous toward the poor.", firstDisproven:"Every major city that imposed rent control saw its housing supply shrink. New York City's rent control, begun in 1943, is the longest-running experiment — and NYC has had a perpetual housing crisis for 80 years. Stockholm's rent controls created a 20-year waitlist for apartments. San Francisco's strict building regulations made it one of the most expensive cities on earth. Meanwhile, Houston — which has no zoning laws — consistently has the most affordable housing of any major American city. Tokyo reformed its building code to allow more construction and rents have remained flat for decades while every regulated Western city's rents skyrocketed. Vitoria's principle applies directly: when the state sets the terms of exchange above or below what free people would agree to, distortions follow. Rent control reduces supply. Building regulations reduce construction. Public housing concentrates poverty. Every government intervention in housing has made the 'crisis' worse — then the worsening crisis is cited as proof that even MORE intervention is needed.", stillActive:"The most emotionally powerful fallacy because homelessness is visible and devastating. 'People are sleeping on the street and you want to let developers build luxury condos?' is the rhetorical kill shot. But the developers building 'luxury condos' are building NEW supply that takes pressure off existing stock. The construction worker building that condo is earning a living. The materials supplier is growing a business. The neighborhood gains tax revenue. The old 'luxury' units become tomorrow's affordable housing as newer stock comes online — this is called filtering, and it's how every healthy housing market has worked throughout history. But the Social Gospel framework can't accept a solution that works through profit motive rather than state compassion. So the solution that actually works — let people build — is rejected as morally inferior to the solution that has failed for 80 years — let the government control it.", color:"#2A3A6A" },
  { id:"f13", name:"'Economics education is neutral and scientific'", origin:"This is the deepest embedded fallacy because it hides the infection mechanism itself. In 1948, Paul Samuelson published Economics — the textbook that would be used by over 4 million students across 41 editions and become the template for virtually every introductory economics course in the Western world. Samuelson was a committed Keynesian who presented government intervention as settled science rather than one school of thought among many. His textbook framework became THE framework: markets are useful but inherently unstable, prone to 'market failures' that require government correction. Recessions are caused by insufficient demand that government spending must fill. Central banks must manage the money supply to smooth business cycles. This isn't neutral science — it's Ritschl's earthly Kingdom dressed in equations. But because it was presented as math, not theology, nobody recognized it as an ideological choice. The Fabian strategy of institutional permeation reached its ultimate form: you don't need to convince students that socialism is good — you just need to teach them that markets fail and government fixes them, and let them draw the 'obvious' conclusion themselves.", firstDisproven:"The Keynesian consensus collapsed in the 1970s when stagflation — simultaneous high inflation and high unemployment — occurred, something Keynesian models said was impossible. Friedman's monetarism and the Austrian school offered explanations that Keynesian frameworks couldn't. But here's the trick: the textbooks were barely updated. Samuelson's framework survived its own falsification. Students in 2025 are still taught IS-LM models and aggregate demand curves as if the 1970s never happened. Meanwhile, the Austrian school — the intellectual descendants of Salamanca through Menger, Mises, and Hayek — is taught in maybe 3-5 universities in the entire country, if at all. Salamanca itself is mentioned in zero standard textbooks. The result: every student who takes Econ 101 absorbs the assumption that markets fail and government must intervene as if it's physics rather than ideology. They graduate into journalism, law, policy, and politics already pre-loaded with Trail B's theology — they just think it's science.", stillActive:"This is the most dangerous fallacy because it's self-reinforcing. Students taught Keynesian economics become professors who write Keynesian textbooks that teach the next generation. The handful of economists who challenge the framework — Austrian, supply-side, free-banking theorists — are marginalized as 'heterodox' or 'fringe,' which is academic language for heretic. The Fabian strategy worked perfectly: you don't have to ban competing ideas, you just have to make sure they're never assigned. A student can get a PhD in economics from Harvard without ever reading Mises, Hayek, Rothbard, or Salamanca. They will have read Keynes, Samuelson, Stiglitz, and Piketty — all of whom assume the state must manage the economy. The pipeline runs directly from Samuelson's 1948 textbook to today's college students who call themselves socialists. They weren't radicalized by Marx. They were radicalized by Econ 101. Marx just gave them the vocabulary for conclusions their textbook had already planted. And the monks who could have offered an alternative — the ones who said 'only God, not man, can know the just price' — are in no syllabus anywhere on earth.", color:"#4A2A4A" },
  { id:"f14", name:"'The Robber Barons prove capitalism needs to be tamed'", origin:"The most successful historical rebranding in American education. The term 'robber baron' was popularized by Matthew Josephson's 1934 book The Robber Barons, written during the peak of New Deal enthusiasm. Josephson was a Marxist-sympathizing journalist who framed Rockefeller, Carnegie, Vanderbilt, and Morgan as proof that unregulated capitalism produces predatory monopolists who crush workers and consumers. This narrative was absorbed wholesale into American history textbooks and has been taught as settled fact for 90 years. Every AP US History student learns it. Every college survey course repeats it. The Social Gospel provides the moral framing: these men embodied systemic sin, and the Progressive Era's regulations were collective salvation.", firstDisproven:"Historian Burton Folsom distinguished between 'political entrepreneurs' who used government favors (subsidies, tariffs, land grants, exclusive charters) and 'market entrepreneurs' who succeeded through innovation and lower prices. Vanderbilt BROKE the government-subsidized steamship monopoly by offering cheaper fares. Rockefeller reduced the price of kerosene by 90%, making lamp fuel affordable for working families for the first time. Carnegie's steel innovations made bridges, railways, and buildings affordable at scale. The 'robber barons' who were genuinely predatory — like Jay Gould and Credit Mobilier — were predatory specifically because they manipulated government contracts and legislative favors. The distinction is everything: the abuse came from the state-capture side, and the benefit came from the market-competition side. But the textbook narrative collapses both into one category so students can't see the difference.", stillActive:"Ask any American who the 'robber barons' were and they'll list Rockefeller and Carnegie — the market entrepreneurs who lowered prices — not the political entrepreneurs who rigged government contracts. The narrative is so deeply embedded that even business schools teach it. The effect: every student absorbs the lesson that successful businesspeople are inherently predatory and need government to restrain them. This is the foundational myth of American regulatory policy. It's also Rauschenbusch's 'super-personal forces' framework in a history costume — the system produces sin, the state must redeem it. Remove the myth and you remove the moral justification for most of the regulatory state. Which is exactly why it's never removed from the curriculum.", color:"#5A2A3A" },
  { id:"f15", name:"'Late-stage capitalism is collapsing under its own contradictions'", origin:"Pure Marx — the theory that capitalism contains internal contradictions (falling rate of profit, overproduction, concentration of wealth) that will inevitably cause its collapse. Marxist academics in the Frankfurt School (Herbert Marcuse, Theodor Adorno) updated this for the 20th century by adding cultural critique: capitalism doesn't just exploit workers economically, it colonizes their consciousness through consumer culture, making them complicit in their own oppression. This entered universities through critical theory departments in the 1960s-70s, filtered into sociology, English, media studies, and eventually K-12 education through teacher training programs that were themselves housed in universities already saturated with this framework. The phrase 'late-stage capitalism' — used constantly on social media — comes directly from Marxist economist Ernest Mandel's 1975 book. Most people using the phrase have never heard of Mandel. They think it's an observation, not an ideology.", firstDisproven:"Marx predicted capitalism's imminent collapse in 1848. It's been 'late-stage' for 177 years. In that time, global GDP per capita increased over 1,500%. Life expectancy doubled. Infant mortality dropped 90%. Literacy went from 12% to 87% globally. The percentage of humans living in extreme poverty fell from 90% to under 10%. Every material metric of human wellbeing improved dramatically under the system Marx said was about to collapse. The 'contradictions' he identified — falling profit rates, overproduction — turned out to be self-correcting features, not fatal flaws. Profit rates fall in mature industries, which redirects capital to new industries (exactly as Molina's framework would predict: free exchange naturally allocates resources to their highest-value use). Overproduction is corrected by price adjustment. The system Marx said couldn't survive has outlived every system built on his alternative.", stillActive:"'Late-stage capitalism' is used millions of times daily on social media, usually attached to screenshots of expensive hospital bills, absurd housing prices, or corporate greed. The irony: most of these examples are caused by government intervention (healthcare regulation, zoning laws, regulatory capture) not by free markets. But students who were taught Keynesian economics in school, critical theory in college, and Marxist vocabulary on social media have no framework to see the state's fingerprints. They see suffering and the only explanation available is 'capitalism is failing.' The Salamanca framework — which would immediately identify each example as state interference in God's natural order — doesn't exist in their intellectual universe. It was buried in the 1600s. So they reach for Marx, whose framework was disproven in the 1800s but was never removed from the curriculum because the Fabian strategy of institutional permeation made sure it stayed.", color:"#3A2A5A" },
  { id:"f16", name:"'Nordic countries prove socialism works'", origin:"The most common contemporary argument for state intervention. Marxist and progressive thinkers point to Sweden, Denmark, Norway, and Finland as proof that large welfare states, high taxes, and extensive government programs produce better outcomes than free-market capitalism. This argument is embedded in every political discussion, every college dorm debate, every social media thread about healthcare or education. Bernie Sanders built an entire presidential campaign on 'we should be more like Denmark.' The implication: these countries are socialist, they work, therefore socialism works.", firstDisproven:"The Nordic countries are not socialist — their own leaders have said so repeatedly. Denmark's Prime Minister Lars Løkke Rasmussen told Harvard in 2015: 'Denmark is far from a socialist planned economy. Denmark is a market economy.' The Nordic model is built on strong property rights, free trade, low corporate taxes, minimal business regulation, and no minimum wage — all features Salamanca would recognize. Sweden tried actual democratic socialism from 1970 to 1991 — it nearly collapsed. Zero net private job creation for the entire period. Sweden's wealthiest family (the Wallenbergs) threatened to leave. The country reversed course with massive deregulation, school choice, and partial privatization of pensions. The 'socialist' policies people admire (healthcare, education) are funded by the free-market wealth that preceded them and are increasingly supplemented by private alternatives as the public systems strain. Norway's wealth comes from state-owned oil — it's a petro-state, not a model replicable by countries without massive sovereign wealth funds.", stillActive:"This is the fallacy you'll hear every single week in American political discourse. It works because people conflate 'large welfare state' with 'socialism' — they're not the same thing. A large welfare state funded by free-market capitalism is closer to Salamanca than to Marx. But students taught that capitalism equals exploitation and government equals compassion can't parse the distinction. The Nordic model actually proves Salamanca right: free markets create the wealth, and the wealth enables generosity. Remove the free markets and the generosity collapses — as Sweden learned from 1970 to 1991. But this nuance never makes it into the classroom because the textbook framework (Samuelson's Keynesian template) presents government spending as the source of prosperity rather than a beneficiary of it. The monks would have understood immediately: the wealth comes from God's natural order of free exchange. The state can redistribute it, but it cannot create it. And when redistribution becomes excessive, it begins to destroy the free exchange that created the wealth in the first place.", color:"#2A4A5A" },
];

// ─── THE COMPOUNDING EFFECT: HOW INTERVENTION CREATED THE CRISIS BLAMED ON CAPITALISM ───
const compoundingEffects = [
  { id:"ce1", title:"You can't afford a house", blame:"'Greedy landlords and capitalism'", actual:"The Federal Reserve held interest rates near zero for over a decade (2008-2022), flooding the economy with cheap money. Investors — not regular families — used that cheap money to buy up housing as assets. Then COVID money printing created $5 trillion in new dollars that inflated home prices 30-40%. Zoning laws in every major city restrict how much housing can be built. NIMBYism is enforced by local government regulation. Fannie Mae and Freddie Mac — government-created entities — inflated the mortgage market for decades before 2008. The entire housing crisis is a stack of government interventions. Remove the Fed's money printing, remove zoning restrictions, remove government mortgage subsidies, and housing becomes affordable through the same mechanism it was affordable for most of American history: builders build, supply meets demand, prices stabilize. Vitoria explained this in the 1530s. The just price emerges from free exchange. Every intervention distorts it.", color:"#C75A3A" },
  { id:"ce2", title:"Student loans are crushing you", blame:"'Colleges are greedy and capitalism failed education'", actual:"In 1965, the federal government began guaranteeing student loans through the Higher Education Act. In 1978, the Middle Income Student Assistance Act expanded eligibility to everyone regardless of income. In 2010, the government took over student lending entirely through the Health Care and Education Reconciliation Act. Here's what happened: when the government guarantees unlimited loans to any 18-year-old for any degree, colleges have zero incentive to control costs because they get paid regardless. Tuition has risen over 1,200% since 1980 — four times the rate of inflation. This isn't capitalism. No business on earth could raise prices 1,200% and keep customers unless a third party was writing blank checks. The government IS that third party. Remove the federal loan guarantee and colleges would have to compete on price overnight, the same way every other industry does. Meanwhile, the administrative bloat that exploded since the 1980s — diversity offices, compliance departments, associate vice provost for student experience — exists because federal money flows with no market discipline. Azpilcueta would recognize this immediately: artificial money flooding a system with fixed supply of slots drives prices to the sky. The monks described this mechanism in 1556. Congress recreated it in 1965.", color:"#B85A3A" },
  { id:"ce3", title:"Healthcare costs are insane", blame:"'The free market can't handle healthcare'", actual:"America doesn't have free market healthcare. It hasn't since at least 1943, when the IRS ruled that employer-provided health insurance was tax-exempt — a WWII-era accident that permanently tied insurance to employment. Then Medicare and Medicaid in 1965 created massive government-funded demand with no price discipline. Then the HMO Act of 1973 mandated employer-sponsored plans. Then the ACA in 2010 added layers of regulation and mandates. The result: a system where nobody knows what anything costs before they buy it, nobody shops on price, insurance companies negotiate with hospitals behind closed doors, and the government pays roughly 50% of all healthcare spending. This is the opposite of a free market. It's a government-created cartel. In the few healthcare sectors where markets actually function — LASIK eye surgery, cosmetic procedures, direct primary care — prices have FALLEN while quality has improved. LASIK cost $2,200 per eye in 1998 and costs about $1,500 today despite being dramatically better. It fell because patients pay directly so providers compete on price and quality. Every sector where government is the primary payer, prices explode. Every sector where patients pay directly, prices fall. Molina's principle from the 1590s: the just price is what buyers and sellers freely agree on. When a third party pays, the price becomes whatever the provider and the payer negotiate — and the patient is irrelevant.", color:"#A85A3A" },
  { id:"ce4", title:"Wages haven't kept up with productivity", blame:"'Corporations are hoarding all the gains'", actual:"Wages and productivity tracked almost perfectly from 1948 to 1971. Then Nixon took the US off the gold standard and wages decoupled from productivity permanently. This is not a coincidence. When money was anchored to gold, employers couldn't invisibly steal purchasing power from workers through inflation. After 1971, the government could print unlimited money, which inflates asset prices (stocks, real estate) that the wealthy own while the wages of workers buy less every year. This is the hidden tax Mariana called theft in 1609. Your employer gives you a 3% raise. Inflation runs at 5%. You got a 2% pay CUT but it doesn't feel like one because the number on your paycheck went up. Meanwhile, your CEO's stock options tripled because the Fed's money printing inflated asset prices. The inequality you're angry about is real — but it wasn't caused by capitalism. It was caused by the Federal Reserve's monetary policy and the abandonment of sound money. The monks would say: you unmoored money from God's natural order (gold/commodity constraints) and handed it to politicians. Of course they debased it. That's what Juan de Mariana said kings always do.", color:"#986A3A" },
  { id:"ce5", title:"Big tech monopolies control everything", blame:"'Unregulated capitalism creates monopolies'", actual:"Every major tech 'monopoly' either grew through government-granted advantages or maintains its position through regulatory capture. Google's data collection operates under Section 230 — a government liability shield. Facebook acquired Instagram and WhatsApp with no antitrust enforcement from the FTC. Amazon's growth was turbocharged by collecting no sales tax for years while brick-and-mortar competitors did — a government-created advantage. Patent law — a government system — allows tech companies to build legal moats around innovations. The revolving door between Big Tech and government regulators ensures that new regulations are written in ways that large companies can comply with but startups cannot. This is the Gilded Age pattern repeating exactly: the 'monopolist' isn't beating the market — they're capturing the state. And the proposed solution — more regulation — will be written by lobbyists from the same companies it's supposed to regulate. Vitoria would recognize this immediately: the state is not the corrector of market power. The state is the source of market power.", color:"#887A3A" },
  { id:"ce6", title:"AI will take all the jobs and only benefit the rich", blame:"'We need to tax AI and redistribute the gains'", actual:"This is the Luddite fallacy in its newest costume, now with a Social Gospel tax-the-rich bow on top. The power loom was going to destroy all jobs. The automobile was going to destroy all jobs. The computer was going to destroy all jobs. The internet was going to destroy all jobs. Each time: more jobs were created than destroyed, at higher wages, because efficiency frees up resources for new industries that didn't exist before. AI will do the same thing — but the interventionist playbook is already being deployed. Tax AI companies. Create universal basic income funded by money printing. Regulate AI development so only large companies with compliance departments can do it (regulatory capture again). The 'tax the rich' framing sounds like justice but it's the same Fabian strategy: use populist moral language to justify expanding state control over the economy. The actual effect of an AI tax: slower innovation, fewer startups, more consolidation into large companies that can afford the compliance costs — which means MORE monopoly power, not less. Molina's insight from the 1590s applies perfectly: when new efficiencies emerge, the just price of goods falls and everyone benefits — unless the state intervenes to capture the gains. The monks understood that human creativity, made in God's image, is the source of abundance. Taxing it doesn't redistribute abundance. It destroys it.", color:"#788A3A" },
  { id:"ce7", title:"'Tax the rich' will fix inequality", blame:"'The wealthy aren't paying their fair share'", actual:"The top 1% of earners pay approximately 46% of all federal income taxes. The top 10% pay about 74%. The bottom 50% pay approximately 3%. The 'fair share' argument has no mathematical definition — it's a theological claim dressed as economics. Rauschenbusch's framework: wealth concentration is systemic sin, redistribution is collective salvation. But trace what actually happens when you raise taxes on 'the rich': they move — New York lost $19.5 billion in adjusted gross income to outmigration between 2020-2022. They restructure — corporate inversions, trusts, offshore accounts. They pass costs through — higher prices, lower wages, fewer jobs. The people who actually pay are the upper-middle class professionals who can't afford the lawyers and accountants that the truly wealthy use. Meanwhile, the tax revenue goes to a government that spent $6.1 trillion in 2023, runs $1.7 trillion annual deficits, and has $34 trillion in national debt. The money doesn't go to 'the people.' It goes to defense contractors, pharmaceutical companies with Medicare pricing power, debt interest payments, and administrative bureaucracy. 'Tax the rich' is the Social Gospel's most effective emotional weapon because it frames state expansion as moral justice. But Salamanca's framework asks the real question: who benefits when you give more money to the institution that has already demonstrated it will waste it, print more when it runs out, and debase the currency that working people depend on?", color:"#689A3A" },
  { id:"ce8", title:"You need government to protect you from corporations", blame:"'Without regulation, companies would poison you and exploit you'", actual:"The FDA was captured by pharmaceutical companies decades ago — 75% of its drug review budget comes from fees paid by the companies it regulates. The FAA let Boeing self-certify the 737 MAX. The EPA's regulations create compliance costs that large corporations use as barriers to entry against smaller competitors. The SEC failed to catch Bernie Madoff despite being told directly. Regulatory agencies don't protect you from corporations — they protect corporations from competition while providing the illusion of safety. This is public choice theory, formalized by James Buchanan who won the Nobel Prize for it: regulators are self-interested humans who respond to incentives, not angels pursuing the public good. The companies being regulated have every incentive to spend millions on lobbying to shape regulations in their favor. You, the consumer, have no corresponding incentive to monitor. The result: every regulatory agency eventually serves the industry it's supposed to police. The Salamanca monks would not be surprised. They said only God can know the just price — meaning no human institution has the knowledge or the virtue to manage economic outcomes for everyone. When you give that power to a human institution, the powerful will capture it. Every time. The real consumer protection is competition — the ability to choose another provider, to start a rival business, to punish bad companies by taking your money elsewhere. Regulation removes that power and replaces it with bureaucratic theater.", color:"#58AA3A" },
];

// ─── THE WAKE-UP: SPEAKING DIRECTLY TO THE GENERATION ───
const wakeUpPoints = [
  { id:"wu1", title:"You weren't born with these beliefs", detail:"Nobody is born thinking 'the government should manage the economy.' That belief was installed in you — through a specific chain of theological decisions, political strategies, and curriculum choices that you can now trace by name, date, and institution. Kant removed God from knowledge. Ritschl turned the Kingdom of God into a political project. Rauschenbusch fused it with Fabian socialism. Samuelson embedded it into every Econ 101 textbook. Your teachers taught it to your teachers. You absorbed it as 'how the world works.' It's not how the world works. It's one theological interpretation of how the world should work — and the competing interpretation was buried in the 1600s." },
  { id:"wu2", title:"Every problem you're angry about was caused by the 'solution' you've been taught to demand", detail:"Can't afford a house? Government money printing and zoning laws. Drowning in student debt? Government loan guarantees removed all price discipline from colleges. Healthcare costs insane? Government payment systems destroyed price transparency. Wages not keeping up? Government abandoned sound money in 1971. Big tech monopolies? Government-granted legal shields, tax advantages, and regulatory capture. You're living in the consequences of 50+ years of compounding government intervention — and you've been taught to blame capitalism, which hasn't actually existed in your lifetime. You've never experienced a free market. You've experienced a state-managed economy that calls itself capitalism so that when it fails, free markets take the blame and the state gets more power. That's not an accident." },
  { id:"wu3", title:"'Tax the rich' is the new 'pray for the Kingdom' — same theology, different century", detail:"Rauschenbusch said systemic sin requires systemic redemption through state power. That's literally what 'tax the rich and redistribute' is — collective salvation through government. The emotional appeal is identical to a revival sermon: there is sin (inequality), there is a villain (the wealthy), there is a savior (the state), and there is a congregation (you). The call to action is the same: surrender your individual agency to the collective, trust the institution, and salvation will come. But the institution has $34 trillion in debt, prints money that steals your purchasing power, and is captured by the very corporations you want it to regulate. You're tithing to a church that's burning your offering." },
  { id:"wu4", title:"The politicians either don't understand what they're doing or they do", detail:"Option A: They genuinely believe government spending solves problems because they were educated in the same Keynesian/Social Gospel framework you were. They've never read Salamanca, Mises, Hayek, or Rothbard. They don't know that the quantity theory of money was discovered in 1556. They don't understand that every dollar they spend must be taxed, borrowed, or printed. They're true believers in a theology they don't recognize as theology. Option B: They understand perfectly and they're doing it on purpose. Every crisis created by intervention becomes the justification for more intervention. Every regulation captures more of the economy under political control. Every new program creates a constituency dependent on its continuation. The incentive structure of democratic politics rewards spending, punishes saving, and makes every problem worse in ways that create demand for more political solutions. Option A is ignorance. Option B is strategy. Either way, you pay. Salamanca's monks knew this in the 1500s — they said the state will always seek to expand its power over markets because power is what states do. The only constraint is God's natural order, expressed through free exchange. Remove that constraint and the state has no limit." },
  { id:"wu5", title:"The real red pill: you don't need the state to save you", detail:"Booker T. Washington built Black Wall Street — 600 businesses, banks, hospitals, a private airplane — with zero government assistance, in the most hostile racial environment in American history. He did it through free enterprise, voluntary exchange, and community self-determination. The state destroyed it. Then the state said: see, you need us. That's the pattern. The state creates the problem, blames the market, and offers itself as the solution. The solution makes it worse. Repeat. Bitcoin is the first technology that lets ordinary people opt out of state-controlled money since Nixon closed the gold window in 1971. Entrepreneurship is the first path to wealth that doesn't require permission from a licensing board, a regulator, or a politician. The information to see through the narrative is now freely available — you're reading it right now. The monks who first said 'free markets are God's design' were buried for 400 years. The economists who tried to resurrect them were marginalized. The history that proves them right was rewritten. But the ideas survived because they're true. And truth doesn't need an institution to protect it. It just needs someone willing to look." },
];

// ─── HELPERS ───
const allNodes = [...trailA, ...trailB];
const findNode = (id) => allNodes.find(n => n.id === id);
const getTrail = (id) => trailA.find(n => n.id === id) ? "A" : "B";

// ─── LIGHT PALETTE ───
const P = {
  bg:"#FAFAF7", card:"#fff", text:"#1a1a1a", sub:"#555", faint:"#999", border:"#e8e5df",
  goldDark:"#8B6914", gold:"#B8860B", goldLight:"#F5ECD7", goldBorder:"#D4B56A",
  tealDark:"#1A6B6A", teal:"#2A8F8E", tealLight:"#E0F2F1", tealBorder:"#6BB8B7",
  red:"#B34233", redLight:"#FDF0EE", redBorder:"#D4837A",
};

function ScrollNode({ node, trail, onNav }) {
  const [open, setOpen] = useState(false);
  const isA = trail === "A";
  const accent = isA ? P.goldDark : P.tealDark;
  const bg = isA ? P.goldLight : P.tealLight;
  const bdr = isA ? P.goldBorder : P.tealBorder;
  return (
    <div style={{ marginBottom:"2px" }}>
      <div onClick={()=>setOpen(!open)} style={{ cursor:"pointer", padding: node.isMilestone?"24px 28px":"20px 24px", background: open ? bg : P.card, border:`1px solid ${open ? bdr : P.border}`, borderLeft:`4px solid ${accent}`, transition:"all 0.3s", borderRadius:"4px" }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
          <div style={{ flex:1 }}>
            <div style={{ fontFamily:"'Space Mono',monospace", fontSize:"10px", letterSpacing:"2px", color:accent, marginBottom:"5px", fontWeight:600 }}>{node.year}</div>
            <div style={{ fontFamily:"'Crimson Text',serif", fontSize: node.isMilestone?"20px":"17px", color:P.text, fontWeight: node.isMilestone?700:600, marginBottom:"6px", lineHeight:1.3 }}>{node.name}</div>
            <div style={{ fontFamily:"'Crimson Text',serif", fontSize:"14px", color:P.sub, fontStyle:"italic", lineHeight:1.5 }}>"{node.quote}"</div>
          </div>
          <div style={{ fontFamily:"'Space Mono',monospace", fontSize:"16px", color:accent, marginLeft:"12px", transform:open?"rotate(90deg)":"none", transition:"transform 0.2s" }}>›</div>
        </div>
      </div>
      {open && (
        <div style={{ padding:"24px 28px", background:bg, borderLeft:`4px solid ${accent}`, borderBottom:`1px solid ${bdr}`, borderRight:`1px solid ${bdr}`, borderRadius:"0 0 4px 4px", marginTop:"-1px" }}>
          <div style={{ fontFamily:"'Crimson Text',serif", fontSize:"15px", color:P.text, lineHeight:1.9, marginBottom:"20px" }}>{node.detail}</div>
          {node.connects?.length > 0 && <div>
            <div style={{ fontFamily:"'Space Mono',monospace", fontSize:"8px", letterSpacing:"2px", color:P.sub, marginBottom:"10px" }}>CONNECTED NODES</div>
            <div style={{ display:"flex", flexWrap:"wrap", gap:"6px" }}>{node.connects.map(c=>{
              const cn=findNode(c); if(!cn) return null; const ct=getTrail(c); const cc=ct==="A"?P.goldDark:P.tealDark;
              return <div key={c} onClick={(e)=>{e.stopPropagation();onNav(c)}} style={{ cursor:"pointer", padding:"5px 12px", border:`1px solid ${cc}40`, borderRadius:"3px", fontFamily:"'Crimson Text',serif", fontSize:"13px", color:cc, background:`${cc}08` }}>{cn.name} <span style={{ fontFamily:"'Space Mono',monospace", fontSize:"8px", opacity:0.5 }}>{ct}</span></div>;
            })}</div>
          </div>}
        </div>
      )}
    </div>
  );
}

function Modal({ children, onClose }) {
  return (<div style={{ position:"fixed", top:0, left:0, right:0, bottom:0, zIndex:1000, display:"flex", alignItems:"center", justifyContent:"center", background:"rgba(0,0,0,0.4)", backdropFilter:"blur(8px)", padding:"16px" }} onClick={onClose}><div onClick={e=>e.stopPropagation()} style={{ maxWidth:"640px", width:"100%", background:P.card, padding:"36px 32px", position:"relative", maxHeight:"85vh", overflowY:"auto", borderRadius:"8px", boxShadow:"0 20px 60px rgba(0,0,0,0.15)" }}>{children}<div onClick={onClose} style={{ marginTop:"28px", cursor:"pointer", fontFamily:"'Space Mono',monospace", fontSize:"9px", letterSpacing:"2px", color:P.faint, textAlign:"center" }}>CLOSE</div></div></div>);
}

function Section({ title, sub, hint, color, open, onToggle, children }) {
  return (<div style={{ maxWidth:"900px", margin:"0 auto", padding:"0 24px 20px" }}><div onClick={onToggle} style={{ cursor:"pointer", textAlign:"center", padding:"24px", border:`1px solid ${P.border}`, background:P.card, borderRadius:"6px", boxShadow:"0 1px 3px rgba(0,0,0,0.04)" }}><div style={{ fontFamily:"'Space Mono',monospace", fontSize:"10px", letterSpacing:"3px", color, marginBottom:"6px" }}>{open?"▼":"▶"} {title}</div><div style={{ fontFamily:"'Crimson Text',serif", fontSize:"17px", color:P.sub }}>{sub}</div>{hint&&<div style={{ fontFamily:"'Crimson Text',serif", fontSize:"12px", color:P.faint, marginTop:"6px", fontStyle:"italic" }}>{hint}</div>}</div>{open&&<div style={{ marginTop:"12px" }}>{children}</div>}</div>);
}

